#include "ntp_time.h"
#include <WiFi.h>
#include <time.h>
void ntp_setup(const char*tz,const char*srv){configTime(0,0,srv);setenv("TZ",tz,1);tzset();Serial.println("[ntp] OK");}
String ntp_get_time(){struct tm t;if(!getLocalTime(&t))return"--:--:--";char buf[9];strftime(buf,sizeof(buf),"%H:%M:%S",&t);return String(buf);}
String ntp_get_date(){struct tm t;if(!getLocalTime(&t))return"----/--/--";char buf[11];strftime(buf,sizeof(buf),"%Y/%m/%d",&t);return String(buf);}
unsigned long ntp_get_epoch(){time_t now;time(&now);return now;}
